Default resolution function: separate from schema (schema only handles parsing; runtime resolves mode→mechanism mapping). Implement as a small util:
```typescript
function resolveCheckpointMechanism(checkpointId: string, config: BoberConfig, cliOverride?: string, cliOverrideAll?: boolean): string {
  if (cliOverrideAll && cliOverride) return cliOverride;
  const override = config.pipeline?.checkpointOverrides?.[checkpointId];
  if (override) return override;
  if (cliOverride) return cliOverride;
  if (config.pipeline?.checkpointMechanism) return config.pipeline.checkpointMechanism;
  return config.pipeline?.mode === 'careful' ? 'disk' : 'noop';
}
